import json
import orjson
import pytest

def test_json_serialization(benchmark):
    data = {"users": [{"id": i, "name": f"User {i}"} for i in range(1000)]}
    result = benchmark.pedantic(lambda: orjson.dumps(data), iterations=100, rounds=10)
    assert result  # non-empty bytes

def test_json_stdlib(benchmark):
    data = {"users": [{"id": i, "name": f"User {i}"} for i in range(1000)]}
    result = benchmark.pedantic(lambda: json.dumps(data), iterations=100, rounds=10)
    assert result

# Run: pytest --benchmark-compare --benchmark-only

import time
from sqlalchemy import event
from sqlalchemy.engine import Engine

@event.listens_for(Engine, "before_cursor_execute")
def before_execute(conn, cursor, statement, parameters, context, executemany):
    conn.info.setdefault("query_start_time", []).append(time.perf_counter())

@event.listens_for(Engine, "after_cursor_execute")
def after_execute(conn, cursor, statement, parameters, context, executemany):
    total = time.perf_counter() - conn.info["query_start_time"].pop()
    if total > 0.1:
        import logging
        logging.warning("SLOW QUERY (%.3fs): %s", total, statement[:120])
